sp_widget.client_script:
function clientController($scope, $rootScope, $http, $location, spUtil, $interpolate, $log, spAriaUtil) {
    //------------------------------------------------------------------------------------------------------------------------
    // COMPANY: DISCOVER TECHNOLOGIES
    // CUSTOMIZED BY: KARINA TORRES
    // RECURSIVE LIST TREE
    //------------------------------------------------------------------------------------------------------------------------
    var c = this;
	spUtil.recordWatch($scope, $scope.data.table, "sys_id=" + $scope.data.sys_id);
    var onListClick = $scope.$on('$sp.list.click', refreshWidget);
    var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);

    function refreshWidget() {
        $scope.server.update();
    }

	c.openLink = function(href){
	$location.url(href);
	};
	c.findChildren = function(id){
		var taskChildren =[];
		for (var i = 0; i < c.data.tasks.length; i++) {
			if(c.data.tasks[i].parent == id){
				taskChildren.push(c.data.tasks[i]);
			}
	}
		return taskChildren;
	};
	c.findCurrentTask = function(id){
		var currentTask = {};
		for (var i = 0; i < c.data.tasks.length; i++) {
			if(c.data.tasks[i].sys_id == id){
				currentTask = c.data.tasks[i];
			}
		}
		return currentTask;
	};
	c.collapse= function(id,event){
		var currentTask = c.findCurrentTask(id);
		var taskChildren = c.findChildren(id);

		if($("#span" + currentTask.sys_id).hasClass( "glyphicon-chevron-down" )){
				c.collapse_1 (id);

		} 
		else if($("#span" + currentTask.sys_id).hasClass( "glyphicon-chevron-right" )){
			c.expand(id);
		}
		event.stopPropagation();
	};
	c.changeState = function(id){
		for(var r=0; r < c.data.tasks; r++){
			if(c.data.tasks[r].sys_id == id){
				c.data.tasks[r].state.expanded = !c.data.tasks[r].state.expanded;
			}
		}
	};
	c.collapse_1 = function(id){

		var currentTask = c.findCurrentTask(id);
		var taskChildren = c.findChildren(id);


			for(var x=0; x < taskChildren.length; x++){
				$("#span" + currentTask.sys_id).removeClass( "glyphicon-chevron-down" );
				$("#span" + currentTask.sys_id).addClass( "glyphicon-chevron-right" );
			//	$( "#" + taskChildren[x].sys_id ).css("background-color",color)
				$( "#" + taskChildren[x].sys_id ).css("display","none");
			c.collapse_1(taskChildren[x].sys_id );
			}
	};

	c.expand = function(id){
		var currentTask = c.findCurrentTask(id);
		var taskChildren = c.findChildren(id);

			for(var x=0; x < taskChildren.length; x++){
				$("#span" + currentTask.sys_id).removeClass( "glyphicon-chevron-right" );
				$("#span" + currentTask.sys_id).addClass( "glyphicon-chevron-down" );
				var color = 'red';
				//$( "#" + taskChildren[x].sys_id ).css("background-color",color)
				$( "#" + taskChildren[x].sys_id ).css("display","block");

			c.expand(taskChildren[x].sys_id );

		}
	};




}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: AYMAN ALZYOUD && KARINA TORRES 
// RECURSIVE LIST TREE
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 08.31.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

div.panel-heading {
  font-size: 16px;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif;
}

span.indent {
  margin-left: 0px!important;
}

.node-task-tree {
  border-top-right-radius: 0px !important;
  border-top-left-radius: 0px !important;
  border-bottom-right-radius: 0px !important;
  border-bottom-left-radius: 0px !important;
}

.list-group-item {
	padding-right: 10px!important;
  padding-bottom: 20px!important;
  border:0px;
}

ul.list-group {
  background-color: $tasklistview-bg;
  border-bottom: 1px dashed #BDBDBD; 
  overflow-x: hidden;
  list-style-type: none;
  margin: auto;
}

li {
	padding: 10px 10px 10px 10px;
  margin: 0px 0px 0px 10px; 
  display: list-item;
  background-color: $tasklistview-bg;
}

li.list-group-item.node-task-tree {
  font-size: 16px important;
  text-decoration: none;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif;
  margin-right 15px;
	list-style: none;
	color: $accessible-placeholder-gray;
  padding: 10px 15px;
}

li.list-group-item.node-task-tree.node-selected {
  background-color: $tasklistview-selected-bg;
  color: darken($accessible-placeholder-gray, 20%);
  border-right: 5px solid $tasklistview-selected-border-right-bg;
  font-weight: 600;
}

li.list-group-item.node-task-tree.selected{
  background-color: $tasklistview-selected-bg;
}


.selected{
	border-right: 5px solid $tasklistview-selected-border-right-bg;
	background-color: $tasklistview-selected-bg;
	font-weight: 600; 
}


//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------

//State = Waiting
span.label.label-Waiting,
span.label.label-pill.label-Waiting {
  	background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

//State = Unassigned
span.label.label-Unassigned,
span.label.label-pill.label-Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text; 
}

//State = Assigned
span.label.label-Assigned,
span.label.label-pill.label-Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
}

//State = Accepted
span.label.label-Accepted,
span.label.label-pill.label-Accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}

//State = Rejected
span.label.label-Rejected,
span.label.label-pill.label-Rejected {
 		background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

//State = Work in Scheduled
span.label.label-Work.Scheduled,
span.label.label-pill.label-Work.Scheduled {
  	background-color: $state-workscheduled-bg;
		color: $state-workscheduled-text;
}

//State = Work in Progress
span.label.label-Work.in.Progress,
span.label.label-pill.label-Work.in.Progress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

//State = In Review
span.label.label-In.Review,
span.label.label-pill.label-In.Review {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

//State = Rework
span.label.label-Rework,
span.label.label-pill.label-Rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

//State = Close Complete
span.label.label-Completed,
span.label.label-pill.label-Completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}

//State = Close Incomplete
span.label.label-Closed.Incomplete,
span.label.label-pill.label-Closed.Incomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

//State = Close Skipped
span.label.label-Cancelled ,
span.label.label-pill.label-Cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

sp_widget.script:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// RECURSIVE TASK LIST TREE
//------------------------------------------------------------------------------------------------------------------------

//------------------------------------------------------------------------------------------------------------------------
// INITIALIZE VARIABLES
//------------------------------------------------------------------------------------------------------------------------
(function() {
	data.results = [];

	var sys_id_topparenttask = null;
	data.sys_id_currenttask = null;

	if ($sp.getParameter("table") == 'x_153465_discovert_route_task_instance') {
		data.sys_id_currenttask = $sp.getParameter("sys_id");
		sys_id_topparenttask = $sp.getParameter("sys_id");
	} else return;

	if (!data.sys_id_currenttask) {
		data.id = null;
		return;
	}

	data.sys_id =  $sp.getParameter("sys_id");

	sys_id_topparenttask = getTopParent(data.sys_id_currenttask);

	data.results.push(getParentDetails(sys_id_topparenttask));

  data.table = $sp.getParameter("table");
	data.sc_catalog = $sp.getValue('x_153465_discovert_route_task_instance');
  data.tasks = getTasks(sys_id_topparenttask, 1);

  data.title = gs.getMessage(options.title);
	//data.page = "discovertasker_processdetails"; //before
	data.page = $sp.getParameter("id");


	// Ayman's custom starts here...

	data.topTask = getTopParent(data.sys_id_currenttask);


})();
function getParentDetails(topParent){
	var result;
		var gr = new GlideRecord('x_153465_discovert_route_task_instance');
			gr.addQuery('sys_id',topParent);
			gr.orderBy('order');
			gr.orderBy('number');
			gr.query();
			if(gr.next()){
				// STRY0051139 - change field to a configurable field.  For now, leave Primary Assignee even though it is on the Tasker Nubmner.  Also leave assigned to, state and work notes, we may make this also configurable, but for now, this works.
				// was text: getTaskTitle(gr.getValue('number'), gr.getValue('short_description'), gr.primary_assignee.getDisplayValue().toString(), gr.assigned_to.getDisplayValue().toString(), gr.state.getDisplayValue(), 0),
				result={
						level : 0,
            sys_id: gr.getValue('sys_id'),
						text: getTaskTitle(gr.getValue('parent'), gr.getValue('task_name'), gr.primary_assignee.getDisplayValue().toString(), gr.assigned_to.getDisplayValue().toString(), gr.state.getDisplayValue(), gr.order.getDisplayValue()),
						state: getStateNode(topParent, 'top'),
					href: '/discovertaskerportal?id=discovertasker_taskdetails&sys_id=' + gr.getValue('sys_id')+'&table=x_153465_discovert_route_task_instance&view=sp'+'&state='+ gr.state+'&order='+ gr.order
        };
			}
	return result;
}
//------------------------------------------------------------------------------------------------------------------------
// GET THE TOP PARENT FOR THE CURRENT SYS_ID
//------------------------------------------------------------------------------------------------------------------------
function getTopParent(sys_id_currenttask) {

	var hasParent;
	var parentID;

	var parentGR = new GlideRecord('x_153465_discovert_route_task_instance');
	parentGR.addQuery('sys_id', sys_id_currenttask);
	parentGR.orderBy('order');
  parentGR.orderBy('number');
	parentGR.query();
	parentGR.next();

	if (parentGR.parent){
			hasParent = true;
			parentID = parentGR.getValue('parent');

			while(hasParent){
				var gp = new GlideRecord('x_153465_discovert_route_task_instance');
				gp.addQuery('sys_id', parentID);
				gp.orderBy('order');
				gp.orderBy('number');
				gp.query();
				gp.next();

				if(gp.parent){
					parentID = gp.getValue('parent');
				}
				else{
					hasParent = false;
				}
			}
	}
	else{
		parentID = sys_id_currenttask;
	}

	return parentID;

}

//------------------------------------------------------------------------------------------------------------------------
// GET TOP PARENT INFORMATION
// Before: Get Routes. Catalog = Template Process
//------------------------------------------------------------------------------------------------------------------------
function getTasks(sys_id_topparenttask,_count) { 

		var result = [];
		var count = _count;
    var parentGR = new GlideRecord('x_153465_discovert_route_task_instance');
    parentGR.addQuery('parent',sys_id_topparenttask);
		parentGR.orderBy('order');
		parentGR.orderBy('number');	
    parentGR.query();

    while (parentGR.next()) {
        if (!$sp.canReadRecord("x_153465_discovert_route_task_instance", parentGR.getUniqueValue())) {
            continue;
        }

				// STRY0051139 - change field to a configurable field.  For now, leave Primary Assignee even though it is on the Tasker Nubmner.  Also leave assigned to, state and work notes, we may make this also configurable, but for now, this works.
				// was text: text: getTaskTitle(parentGR.getValue('number'), parentGR.getValue('short_description'), parentGR.primary_assignee.getDisplayValue().toString(), parentGR.assigned_to.getDisplayValue().toString(), parentGR.state.getDisplayValue(), 0),
        data.results.push({
						level: count,
						parent: parentGR.getValue('parent'),
            sys_id: parentGR.getValue('sys_id'),
						hasChildren: parentGR.getValue('calchaschildren'),
						text: getTaskTitle(parentGR.getValue('parent'), parentGR.getValue('task_name'), parentGR.primary_assignee.getDisplayValue().toString(), parentGR.assigned_to.getDisplayValue().toString(), parentGR.state.getDisplayValue(), parentGR.order.getDisplayValue()),
						state: getStateNode(sys_id_topparenttask, 'top'),
			href: '/discovertaskerportal?id=discovertasker_taskdetails&sys_id=' + parentGR.getValue('sys_id')+'&table=x_153465_discovert_route_task_instance&view=sp'+'&state='+ parentGR.state+'&order='+ parentGR.order
        });
			if(parentGR.calchaschildren){
				getTasks(parentGR.getValue('sys_id'),count + 1);
			}
    }
    return data.results;
}

//------------------------------------------------------------------------------------------------------------------------
// GET TASKS RECURSIVELY
//------------------------------------------------------------------------------------------------------------------------
function getTaskRecursive(task) { 

	var sc = new GlideRecord('x_153465_discovert_route_task_instance');
		sc.addQuery('parent',task.sys_id);
		sc.orderBy('order');
    sc.orderBy('number');
    sc.query();

	while (sc.next()) {
		if (!$sp.canReadRecord("x_153465_discovert_route_task_instance", sc.getUniqueValue())) {
            continue;
        }

        if (!task.nodes) {
            task.nodes = [];
        }

				// STRY0051139 - change field to a configurable field.  For now, leave Primary Assignee even though it is on the Tasker Nubmner.  Also leave assigned to, state and work notes, we may make this also configurable, but for now, this works.
				// was text: text: text: getTaskTitle(sc.getValue('number'), sc.getValue('short_description'), sc.primary_assignee.getDisplayValue().toString(), sc.assigned_to.getDisplayValue().toString(), sc.state.getDisplayValue(), sc.task_order),
        task.nodes.push(getTaskRecursive({
            sys_id: sc.getValue('sys_id'),
            text: getTaskTitle(sc.getValue('parent'), sc.getValue('task_name'), sc.primary_assignee.getDisplayValue().toString(), sc.assigned_to.getDisplayValue().toString(), sc.state.getDisplayValue(), sc.task_order),
			parent: sc.getValue('parent'),
						state: getStateNode(sc.getValue('sys_id')),
						href: '/discovertaskerportal?id=discovertasker_taskdetails&sys_id=' + sc.getValue('sys_id')+'&table='+'x_153465_discovert_route_task_instance&view=sp'+'&state='+ sc.state	
        }));
    }
    return task;
}


//------------------------------------------------------------------------------------------------------------------------
// GET COLLAPSE/EXPAND
//------------------------------------------------------------------------------------------------------------------------
function getStateNode(taskSysId,type) {
    var currentSysId = $sp.getParameter("sys_id"); 
	var parents = getAllParents(taskSysId);

		if (type == 'top' && taskSysId == currentSysId) {
        return {
            selected: true,
            expanded: true
        };
    }

		if (parents.indexOf(taskSysId) > -1 || type == 'top'){
				return {
            expanded: true
        };
    }

    if (taskSysId == currentSysId) {
        return {
            selected: true,
            expanded: true
        };
    }else {
			return {
            selected: false,
            expanded: false
        };
		}
    return {};
}

function getAllParents(taskSysId) {
  var result = [];
	var allParents = "";
	var parent;

  var sc = new GlideRecord('x_153465_discovert_route_task_instance');
	sc.addQuery('sys_id',taskSysId);
	sc.orderBy('order');
  sc.orderBy('number');
  sc.query();

	while (sc.next()) {
		parent = sc.getValue('parent');
        if (parent) {
						allParents += " | " + parent.toString();
        }
	}
	return allParents;
}



//------------------------------------------------------------------------------------------------------------------------

// STRY0051139 - change field to a configurable field.  For now, leave Primary Assignee even though it is on the Tasker Nubmner.  Also leave assigned to, state and work notes, we may make this also configurable, but for now, this works.
// was function getTaskTitle(TaskNumber, Short_Description, Primary_Assignee, Assigned_To, State, Order) {
//------------------------------------------------------------------------------------------------------------------------
// GET TASK TITLE
//------------------------------------------------------------------------------------------------------------------------
function getTaskTitle(parent, TaskNameNumber, Primary_Assignee, Assigned_To, State, Order) {
	var task = {};
	// was - task = {tasknumber: TaskNumber, short_description: Short_Description, primary_asssignee: Primary_Assignee,assigned_to: Assigned_To, State: State, Order: Order};
	if (parent != null) TaskNameNumber = Order + ". " + TaskNameNumber; // NEW
	task = {TaskNameNumber: TaskNameNumber, primary_asssignee: Primary_Assignee,assigned_to: Assigned_To, State: State, Order: Order};

	/*
	if (Order > 0)
		task.Order = Order.toString();

	if (Primary_Assignee.length > 0) 
		task.primary_assignee = Primary_Assignee ;
	*/

	if (Assigned_To.length > 0) 
		task.assigned_to = '(' + Assigned_To + ')';

  var badgeclass = "label label-"+State;
	task.state = State;

	return task;
}
